1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Step = { items: Item[] };
14	type Customer = { yearsWithMHPCO: number };
15	type Scenario = { customer: Customer; steps: Step[] };
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_BASE_PREMIUM = 60;
19	
20	export function processScenario(scenario: unknown): unknown {
21	  const { customer, steps } = scenario as Scenario;
22	  const items = steps[0].items;
23	  const componentCountsByType = new Map<string, number>();
24	  let itemAdjustedSum = 0;
25	  let policyBasePremium = 0;
26	  for (const item of items) {
27	    if (COMPONENT_TYPES.has(item.type)) {
28	      componentCountsByType.set(
29	        item.type,
30	        (componentCountsByType.get(item.type) ?? 0) + 1,
31	      );
32	    } else {
33	      const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
34	      let itemPremium = base;
35	      if (item.cursed) {
36	        itemPremium += base * 0.5;
37	      }
38	      if (item.enchantment !== undefined && item.enchantment >= 5) {
39	        itemPremium += base * 0.3;
40	      }
41	      itemPremium += base * 0.1;
42	      itemAdjustedSum += itemPremium;
43	      policyBasePremium += base;
44	    }
45	  }
46	  for (const [type, count] of componentCountsByType) {
47	    if (count === 3) {
48	      itemAdjustedSum += BLOCK_BASE_PREMIUM + BLOCK_BASE_PREMIUM * 0.1;
49	      policyBasePremium += BLOCK_BASE_PREMIUM;
50	    } else {
51	      const componentBase = BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
52	      itemAdjustedSum += count * (componentBase + componentBase * 0.1);
53	      policyBasePremium += count * componentBase;
54	    }
55	  }
56	  let loyaltyDiscount = 0;
57	  if (customer.yearsWithMHPCO >= 2) {
58	    loyaltyDiscount = policyBasePremium * 0.2;
59	  }
60	  return { results: [{ premium: Math.ceil(itemAdjustedSum - loyaltyDiscount + PROCESSING_FEE) }] };
61	}
